import React, { useEffect, useRef, useState } from "react";
import { useScrollReveal } from "./useScrollAnimation";
import "./HowItWorks.css";

/* progress of ONE element through viewport — bidirectional */
function useElScroll() {
  const ref = useRef(null);
  const [p, setP] = useState(0);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const fn = () => {
      const { top, height } = el.getBoundingClientRect();
      const wh = window.innerHeight;
      setP(Math.max(0, Math.min(1, (wh - top) / (wh + height))));
    };
    fn();
    window.addEventListener("scroll", fn, { passive: true });
    return () => window.removeEventListener("scroll", fn);
  }, []);
  return [ref, p];
}

const STEPS = [
  {
    num: "01", tag: "Step One", title: "Upload to IPFS",
    headline: "CONTENT-ADDRESSED",
    desc: "Your PDF is uploaded to IPFS via Pinata. IPFS runs your file through SHA-256 and returns a Content Identifier — a cryptographic fingerprint of every byte. Any modification produces a completely different CID.",
    details: [
      "SHA-256 hashing of every file byte",
      "Pinata pinning ensures global availability",
      "Even 1 byte change = completely different CID",
      "CID is mathematically unforgeable",
    ],
    code: "const cid = await uploadToPinata(file);\n// → bafybeigdyrzt5sfp7...",
    img: "https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=1200&q=80",
    accent: "#b8922a",
  },
  {
    num: "02", tag: "Step Two", title: "Register On-Chain",
    headline: "IMMUTABLE",
    desc: "Your CID, wallet address, and a network-consensus timestamp are written into the PaperRegistry contract on Polygon. The contract permanently rejects any future attempt to register the same CID.",
    details: [
      "msg.sender cryptographically verifies identity",
      "block.timestamp set by Polygon consensus",
      "Duplicate CIDs rejected at EVM level",
      "No admin, no backdoor — code is the only law",
    ],
    code: "await registry.submitPaper(cid);\n// Confirmed · Block #1,284,920",
    img: "https://images.unsplash.com/photo-1639322537228-f710d846310a?w=1200&q=80",
    accent: "#3d7fff",
  },
  {
    num: "03", tag: "Step Three", title: "Verify Anywhere",
    headline: "TRUSTLESS",
    desc: "Anyone can call getPaper() with a CID. The blockchain returns the author address, timestamp, and precedence status — instantly, permissionlessly, without any trusted third party.",
    details: [
      "Read-only view function — zero gas cost",
      "No wallet or account required to verify",
      "Returns author, timestamp, existence status",
      "Valid as long as Polygon blockchain exists",
    ],
    code: "const [cid, author, ts, exists]\n  = await registry.getPaper(cid);",
    img: "https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=1200&q=80",
    accent: "#1a6b5a",
  },
];

/* One step — image scrolls at parallax, text slides in from the side */
function Step({ step, i }) {
  const [secRef, p] = useElScroll();
  const even = i % 2 === 1;

  // Text enters from the right side for even, left side for odd
  // At p=0 (entering from bottom) text is offset, at p=0.4–0.6 it's settled, exits same direction
  const clamp = (v) => Math.max(0, Math.min(1, v));
  const settled   = clamp((p - 0.2) / 0.25);    // 0→1 as p goes 0.2→0.45
  const unsettled = clamp((p - 0.6) / 0.25);    // 0→1 as p goes 0.6→0.85

  const textProgress = settled - unsettled;       // peaks at 1, goes back to 0
  const textX = even
    ? (1 - textProgress) * 80                    // slides from right
    : (1 - textProgress) * -80;                  // slides from left
  const textOp = 0.1 + textProgress * 0.9;

  // Image parallax — slower than scroll
  const imgY  = (p - 0.5) * -60;               // -30px to +30px

  return (
    <div className={`hiw-step ${even ? "hiw-step--flip" : ""}`} ref={secRef}>

      {/* IMAGE SIDE */}
      <div className="hiw-step__img-col">
        <img
          src={step.img} alt={step.title}
          className="hiw-step__img"
          loading="lazy"
          style={{ transform: `translateY(${imgY}px) scale(1.08)` }}
        />
        <div className="hiw-step__img-ov" />
        <div className="hiw-step__img-num">{step.num}</div>

        {/* Bleeding word OVER image */}
        <div className="hiw-step__img-bleed" style={{ color: `${step.accent}18` }}>
          {step.headline}
        </div>

        {/* Code snippet — slides up on hover */}
        <div className="hiw-step__code-ov">
          <pre className="hiw-step__code" style={{ borderColor: `${step.accent}30` }}>
            {step.code}
          </pre>
        </div>
      </div>

      {/* TEXT SIDE */}
      <div
        className="hiw-step__text-col"
        style={{
          transform: `translateX(${textX}px)`,
          opacity: textOp,
          "--a": step.accent,
        }}
      >
        {/* Giant ghost headline behind text — Ferrari style */}
        <div className="hiw-step__ghost">{step.headline}</div>

        <div className="hiw-step__tag">{step.tag} · {step.num}</div>
        <h3 className="hiw-step__title">{step.title}</h3>
        <p className="hiw-step__desc">{step.desc}</p>
        <ul className="hiw-step__list">
          {step.details.map((d) => (
            <li key={d} className="hiw-step__item">
              <span className="hiw-step__bullet" />
              {d}
            </li>
          ))}
        </ul>
      </div>

    </div>
  );
}

